// Parse the live "Spend Tracker" sheet -> fact_marketing_spend rows.
// Source rows already keyed by header (Excel node keyRow=1 / dataStartRow=2).
// Market -> region; native EUR; signed corrections kept; the "TEST IGNORE" sheet is
// excluded simply by selecting the Spend Tracker worksheet.

function findKey(obj, token) {
  const k = Object.keys(obj).find((k) => k.toLowerCase().indexOf(token) >= 0);
  return k || null;
}
function num(v) {
  const n = Number(String(v == null ? '' : v).replace(/[^0-9.\-]/g, ''));
  return isNaN(n) ? 0 : n;
}
function toISO(v) {
  if (v == null || v === '') return null;
  if (typeof v === 'number') {            // Excel serial date
    const d = new Date(Math.round((v - 25569) * 86400 * 1000));
    return isNaN(d.getTime()) ? null : d.toISOString().slice(0, 10);
  }
  const s = String(v).trim();
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  const t = Date.parse(s);
  return isNaN(t) ? null : new Date(t).toISOString().slice(0, 10);
}
function regionCode(m) {
  const s = String(m || '').trim().toUpperCase();
  if (s === 'NL') return 'NL';
  if (s === 'BELUX') return 'BeLux';
  if (s === 'UK' || s === 'UK & IE' || s === 'UK&IE' || s === 'UKI' || s === 'UK & IRL') return 'UKI';
  return 'UNASSIGNED'; // ALL / blank / anything else
}

const rows = $input.all();
let kDate, kQ, kLine, kAud, kMarket, kStatus, kOwner, kCost, kNotes;
if (rows.length) {
  const r0 = rows[0].json;
  kDate = findKey(r0, 'date'); kQ = findKey(r0, 'quarter'); kLine = findKey(r0, 'budget line');
  kAud = findKey(r0, 'audience'); kMarket = findKey(r0, 'market'); kStatus = findKey(r0, 'status');
  kOwner = findKey(r0, 'owner'); kCost = findKey(r0, 'cost'); kNotes = findKey(r0, 'note');
}

const out = [];
let rowsIn = 0;
for (const item of rows) {
  const j = item.json || {};
  const date = toISO(j[kDate]);
  const amount = num(j[kCost]);
  const market = j[kMarket];
  // skip blank/filler rows (no date and no amount)
  if (!date && amount === 0 && !market) continue;
  if (!date) continue;            // a real spend line always has a date
  rowsIn++;
  out.push({ json: {
    activity_date: date,
    quarter: j[kQ] != null ? String(j[kQ]).trim() : null,
    budget_line: j[kLine] != null ? String(j[kLine]).trim() : null,
    primary_audience: j[kAud] != null ? String(j[kAud]).trim() : null,
    market_raw: market != null ? String(market).trim() : null,
    region_code: regionCode(market),
    status: j[kStatus] != null ? String(j[kStatus]).trim() : null,
    owner: j[kOwner] != null ? String(j[kOwner]).trim() : null,
    amount: amount,
    notes: j[kNotes] != null ? String(j[kNotes]).trim() : null
  } });
}
if (out.length === 0) {
  throw new Error('Budget sync: no spend rows parsed - check the workbook/worksheet selection and the keyRow/dataStartRow offsets (title row sits above the header).');
}
return out;

// Re-emit parsed rows after the delete, so the insert has data even though
// the delete node returns no items.
return $('Parse Budget Rows').all();
